/**
 * Tagify - Lightweight tags input component
 * Simplified version for CMS-Core integration
 * Based on Tagify 4.x pattern
 */
(function(window) {
  'use strict';

  class Tagify {
    constructor(input, settings = {}) {
      this.input = input;
      this.settings = {
        maxTags: settings.maxTags || Infinity,
        duplicates: settings.duplicates !== undefined ? settings.duplicates : false,
        draggable: settings.draggable !== undefined ? settings.draggable : true,
        dropdown: settings.dropdown || { enabled: 1, maxItems: 10 },
        whitelist: settings.whitelist || [],
        callbacks: settings.callbacks || {},
        ...settings
      };

      this.value = [];
      this.DOM = {};

      this.build();
      this.events.bindAll.call(this);
      this.loadInitialValue();
    }

    build() {
      // Create tagify wrapper
      this.DOM.scope = document.createElement('tags');
      this.DOM.scope.className = 'tagify';

      // Create main input
      this.DOM.input = document.createElement('span');
      this.DOM.input.className = 'tagify__input';
      this.DOM.input.contentEditable = true;
      this.DOM.input.setAttribute('role', 'textbox');
      this.DOM.input.setAttribute('aria-label', 'Add tags');

      // Hide original input
      this.input.style.display = 'none';
      this.input.parentNode.insertBefore(this.DOM.scope, this.input);
      this.DOM.scope.appendChild(this.DOM.input);

      // Create dropdown
      this.dropdown = new Dropdown(this);
    }

    loadInitialValue() {
      try {
        const value = this.input.value;
        if (!value) return;

        const tags = JSON.parse(value);
        if (Array.isArray(tags)) {
          tags.forEach(tag => this.addTag(tag, true));
        }
      } catch (e) {
        console.warn('[Tagify] Failed to parse initial value:', e);
      }
    }

    addTag(tagData, skipValidation = false) {
      if (!skipValidation) {
        // Check max tags
        if (this.value.length >= this.settings.maxTags) {
          this.trigger('maxTagsExceeded', { maxTags: this.settings.maxTags });
          return;
        }

        // Check duplicates
        if (!this.settings.duplicates) {
          const exists = this.value.some(t => t.value === tagData.value);
          if (exists) {
            this.trigger('duplicate', tagData);
            return;
          }
        }
      }

      // Create tag DOM element
      const tagElm = this.createTagElement(tagData);

      // Insert before input
      this.DOM.scope.insertBefore(tagElm, this.DOM.input);

      // Add to value
      this.value.push(tagData);
      this.update();

      // Clear input
      this.DOM.input.textContent = '';

      this.trigger('add', { tag: tagElm, data: tagData });
    }

    createTagElement(tagData) {
      const tag = document.createElement('tag');
      tag.className = 'tagify__tag';
      tag.setAttribute('value', tagData.value);

      if (this.settings.draggable) {
        tag.draggable = true;
      }

      const tagText = document.createElement('x');
      tagText.textContent = tagData.label || tagData.value;

      const removeBtn = document.createElement('x');
      removeBtn.className = 'tagify__tag__removeBtn';
      removeBtn.setAttribute('role', 'button');
      removeBtn.setAttribute('aria-label', 'remove tag');
      removeBtn.textContent = '×';

      const wrapper = document.createElement('div');
      wrapper.appendChild(tagText);
      wrapper.appendChild(removeBtn);

      tag.appendChild(wrapper);
      tag.__tagifyTagData = tagData;

      return tag;
    }

    removeTag(tagElm) {
      const tagData = tagElm.__tagifyTagData;

      tagElm.remove();
      this.value = this.value.filter(t => t.value !== tagData.value);
      this.update();

      this.trigger('remove', { tag: tagElm, data: tagData });
    }

    removeAllTags() {
      this.DOM.scope.querySelectorAll('tag').forEach(tag => tag.remove());
      this.value = [];
      this.update();
    }

    update() {
      // Update hidden input with current values
      const values = this.value.map(t => t.value);
      const hiddenInput = this.input.parentNode.querySelector('input[type="hidden"]');
      if (hiddenInput) {
        hiddenInput.value = JSON.stringify(values);
      }

      this.trigger('change', { value: this.value });
    }

    trigger(eventName, detail = {}) {
      const callback = this.settings.callbacks[eventName];
      if (callback && typeof callback === 'function') {
        callback.call(this, detail);
      }

      const event = new CustomEvent(eventName, { detail, bubbles: true });
      this.DOM.scope.dispatchEvent(event);
    }

    events = {
      bindAll() {
        // Input events
        this.DOM.input.addEventListener('input', this.events.onInput.bind(this));
        this.DOM.input.addEventListener('keydown', this.events.onKeydown.bind(this));
        this.DOM.input.addEventListener('blur', this.events.onBlur.bind(this));

        // Tag events (using event delegation)
        this.DOM.scope.addEventListener('click', this.events.onScopeClick.bind(this));

        // Drag events
        if (this.settings.draggable) {
          this.DOM.scope.addEventListener('dragstart', this.events.onDragStart.bind(this));
          this.DOM.scope.addEventListener('dragover', this.events.onDragOver.bind(this));
          this.DOM.scope.addEventListener('drop', this.events.onDrop.bind(this));
        }
      },

      onInput(e) {
        const value = e.target.textContent.trim();
        if (value) {
          this.dropdown.show(value);
        } else {
          this.dropdown.hide();
        }
      },

      onKeydown(e) {
        const value = e.target.textContent.trim();

        if (e.key === 'Enter' || e.key === ',') {
          e.preventDefault();
          if (value) {
            this.addTag({ value, label: value });
          }
        } else if (e.key === 'Backspace' && !value) {
          // Remove last tag
          const tags = this.DOM.scope.querySelectorAll('tag');
          if (tags.length > 0) {
            this.removeTag(tags[tags.length - 1]);
          }
        }
      },

      onBlur(e) {
        setTimeout(() => this.dropdown.hide(), 200);
      },

      onScopeClick(e) {
        if (e.target.classList.contains('tagify__tag__removeBtn')) {
          const tag = e.target.closest('tag');
          if (tag) {
            this.removeTag(tag);
          }
        } else if (e.target === this.DOM.scope) {
          this.DOM.input.focus();
        }
      },

      onDragStart(e) {
        if (e.target.tagName === 'TAG') {
          e.dataTransfer.effectAllowed = 'move';
          e.dataTransfer.setData('text/html', e.target.outerHTML);
          e.target.classList.add('tagify__tag--dragging');
          this._draggingTag = e.target;
        }
      },

      onDragOver(e) {
        if (!this._draggingTag) return;

        e.preventDefault();
        e.dataTransfer.dropEffect = 'move';

        const tag = e.target.closest('tag');
        if (tag && tag !== this._draggingTag) {
          const rect = tag.getBoundingClientRect();
          const midpoint = rect.left + rect.width / 2;

          if (e.clientX < midpoint) {
            tag.parentNode.insertBefore(this._draggingTag, tag);
          } else {
            tag.parentNode.insertBefore(this._draggingTag, tag.nextSibling);
          }
        }
      },

      onDrop(e) {
        e.preventDefault();
        if (this._draggingTag) {
          this._draggingTag.classList.remove('tagify__tag--dragging');

          // Update value array to match DOM order
          const tags = Array.from(this.DOM.scope.querySelectorAll('tag'));
          this.value = tags.map(tag => tag.__tagifyTagData);
          this.update();

          this._draggingTag = null;
        }
      }
    };

    destroy() {
      this.DOM.scope.remove();
      this.input.style.display = '';
    }
  }

  // Dropdown component
  class Dropdown {
    constructor(tagify) {
      this.tagify = tagify;
      this.DOM = {};
      this.build();
    }

    build() {
      this.DOM.dropdown = document.createElement('div');
      this.DOM.dropdown.className = 'tagify__dropdown';
      this.DOM.dropdown.style.display = 'none';
      document.body.appendChild(this.DOM.dropdown);
    }

    show(query) {
      const settings = this.tagify.settings;
      const autocompleteUrl = settings.autocompleteUrl || '/api/tagify/autocomplete';
      const target = this.tagify.input.dataset.target || '';
      const vocabulary = this.tagify.input.dataset.vocabulary || '';

      // Fetch suggestions
      fetch(`${autocompleteUrl}?query=${encodeURIComponent(query)}&target=${target}&vocabulary=${vocabulary}`)
        .then(res => res.json())
        .then(items => {
          this.render(items);
          this.position();
        })
        .catch(err => {
          console.error('[Tagify] Autocomplete failed:', err);
        });
    }

    render(items) {
      if (!items || items.length === 0) {
        this.hide();
        return;
      }

      this.DOM.dropdown.innerHTML = items.map(item => `
        <div class="tagify__dropdown__item" data-value="${item.value}">
          ${item.label || item.value}
        </div>
      `).join('');

      // Add click handlers
      this.DOM.dropdown.querySelectorAll('.tagify__dropdown__item').forEach(item => {
        item.addEventListener('click', () => {
          this.tagify.addTag({
            value: item.dataset.value,
            label: item.textContent.trim()
          });
          this.hide();
        });
      });

      this.DOM.dropdown.style.display = 'block';
    }

    position() {
      const rect = this.tagify.DOM.scope.getBoundingClientRect();
      this.DOM.dropdown.style.position = 'absolute';
      this.DOM.dropdown.style.top = `${rect.bottom + window.scrollY}px`;
      this.DOM.dropdown.style.left = `${rect.left + window.scrollX}px`;
      this.DOM.dropdown.style.width = `${rect.width}px`;
    }

    hide() {
      this.DOM.dropdown.style.display = 'none';
    }
  }

  // Initialize Tagify on page load
  function initTagify() {
    document.querySelectorAll('.tagify-input[data-tagify="true"]').forEach(input => {
      if (input._tagify) return; // Already initialized

      try {
        const settings = JSON.parse(input.dataset.settings || '{}');
        input._tagify = new Tagify(input, settings);
      } catch (e) {
        console.error('[Tagify] Initialization failed:', e);
      }
    });
  }

  // Auto-init on DOMContentLoaded
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', initTagify);
  } else {
    initTagify();
  }

  // Export to window
  window.Tagify = Tagify;

})(window);
